import { Link } from 'react-router-dom';
import { useState, useEffect } from 'react';

const categories = ['Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact'];

/* ═══════════════════════════════════════════════
   1. CATEGORY EXPLORER
═══════════════════════════════════════════════ */
const CATEGORY_DATA = [
  { name: 'Technology',    icon: '⚡', count: 94,  funded: '$890K', color: '#00d4aa', bg: 'rgba(0,212,170,0.07)',   border: 'rgba(0,212,170,0.2)' },
  { name: 'Health',        icon: '🧬', count: 67,  funded: '$620K', color: '#06b6d4', bg: 'rgba(6,182,212,0.07)',   border: 'rgba(6,182,212,0.2)' },
  { name: 'Education',     icon: '📚', count: 53,  funded: '$410K', color: '#8b5cf6', bg: 'rgba(139,92,246,0.07)',  border: 'rgba(139,92,246,0.2)' },
